(() => {
    interface ICircularDeep {
      name: string;
      big: bigint;
      embedded: {hello: string; child?: ICircularDeep};
    }
    interface RootNotCircular {
      isRoot: true;
      ciChild: ICircularDeep;
    }
    return {build: () => createValidate<RootNotCircular>(), buildErrors: () => noErrs(createGetValidationErrors<RootNotCircular>())};
  })()

() => {
    // The recursive child is a `circular(...)`; the non-circular root is a plain
    // schema referencing it — no hand-written types at all.
    const icd = RT.circular((self) =>
      RT.object({
        name: RT.string(),
        big: RT.bigint(),
        embedded: RT.object({hello: RT.string(), child: RT.optional(self)}),
      })
    );
    const root = RT.object({isRoot: RT.literal(true), ciChild: icd});
    return createValidate(root);
  }

(() => {
    interface ICircularDeep {
      name: string;
      big: bigint;
      embedded: {hello: string; child?: ICircularDeep};
    }
    interface RootNotCircular {
      isRoot: true;
      ciChild: ICircularDeep;
    }
    return {
      build: () => {
        const check = typia.createIs<RootNotCircular>();
        return (v) => check(v);
      },
      buildErrors: () => {
        const val = typia.createValidate<RootNotCircular>();
        return (v) => val(v).success;
      },
    };
  })()

c(
    Type.Object({
      isRoot: Type.Literal(true),
      ciChild: Type.Recursive((This) =>
        Type.Object({
          name: Type.String(),
          big: Type.BigInt(),
          embedded: Type.Object({hello: Type.String(), child: Type.Optional(This)}),
        })
      ),
    })
  )

c(z.lazy(() => {
    const ciDeep: z.ZodType = z.object({
      name: z.string(),
      big: z.bigint(),
      embedded: z.object({hello: z.string(), child: z.lazy(() => ciDeep).optional()}),
    });
    return z.object({isRoot: z.literal(true), ciChild: ciDeep});
  }))
